import { BrowserRouter, Routes, Route, NavLink, Link } from 'react-router-dom';
import Dashboard from './pages/Dashboard';
import Teams from './pages/Teams';
import TeamDetail from './pages/TeamDetail';
import Matches from './pages/Matches';
import MatchDetail from './pages/MatchDetail';

function Navbar() {
  const linkClass = ({ isActive }) =>
    `flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition-all ${
      isActive ? 'bg-white text-emerald-900 shadow-sm' : 'text-emerald-50 hover:bg-white/15'
    }`;

  return (
    <nav className="sticky top-0 z-20 border-b border-emerald-900/20 bg-gradient-to-r from-emerald-900 via-emerald-800 to-lime-700 shadow-xl">
      <div className="max-w-7xl mx-auto px-4 py-3 flex items-center gap-2 flex-wrap">
        <Link to="/" className="flex items-center gap-2.5 mr-4">
          <span className="text-2xl">🏏</span>
          <span className="text-white font-semibold text-lg tracking-tight">Cricket League Ledger</span>
        </Link>
        <NavLink to="/" end className={linkClass}>🏠 Dashboard</NavLink>
        <NavLink to="/teams" className={linkClass}>👥 Teams</NavLink>
        <NavLink to="/matches" className={linkClass}>🏆 Matches</NavLink>
      </div>
    </nav>
  );
}

export default function App() {
  return (
    <BrowserRouter>
      <div className="app-shell">
        <Navbar />
        <main className="page-shell">
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/teams" element={<Teams />} />
            <Route path="/teams/:id" element={<TeamDetail />} />
            <Route path="/matches" element={<Matches />} />
            <Route path="/matches/:id" element={<MatchDetail />} />
          </Routes>
        </main>
      </div>
    </BrowserRouter>
  );
}
